SELECT id, exam_type_id, exam_subject_id, title, time_limit_min, is_active, created_at
FROM exam_paper

    AND exam_type_id = #{typeId}
    AND exam_subject_id = #{subjectId}
    AND is_active = #{isActive}

ORDER BY id

